package store

import "errors"

var ErrNotFound = errors.New("store: not found")

package store

import (
	"time"
)

type SandboxInfo struct {
	SandboxID   string       `json:"sandboxId"`
	Name        string       `json:"name"`
	SessionID   string       `json:"sessionId"`
	Kind        string       `json:"kind"`
	Namespace   string       `json:"namespace"`
	EntryPoints []EntryPoint `json:"entryPoints"`
	ExpiresAt   time.Time    `json:"expiresAt"`
	CreatedAt   time.Time    `json:"createdAt"`
}

type EntryPoint struct {
	Path     string `json:"path"`
	Protocol string `json:"protocol"`
	Endpoint string `json:"endpoint"`
	Name     string `json:"name,omitempty"`
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"sync"
	"time"

	"github.com/go-redis/redis/v9"
	"k8s.io/klog/v2"
)

const (
	SessionKeyPrefix     = "session:"
	SessionExpiryKey     = "session:expiry"
	SessionLastActivity  = "session:last_activity"
	DefaultRedisAddr     = "localhost:6379"
)

type RedisStore struct {
	client *redis.Client
	mu     sync.RWMutex
}

var _ Store = (*RedisStore)(nil)

func NewRedisStore(addr, password string) (*RedisStore, error) {
	if addr == "" {
		addr = DefaultRedisAddr
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
	})

	store := &RedisStore{
		client: client,
	}

	return store, nil
}

func (r *RedisStore) Ping(ctx context.Context) error {
	pong, err := r.client.Ping(ctx).Result()
	if err != nil {
		return fmt.Errorf("redis ping failed: %w", err)
	}
	if pong != "PONG" {
		return fmt.Errorf("unexpected redis ping response: %s", pong)
	}
	return nil
}

func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := r.client.Get(ctx, key).Bytes()
	if err != nil {
		if err == redis.Nil {
			return nil, ErrNotFound
		}
		return nil, fmt.Errorf("failed to get sandbox: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("sandbox expiresAt cannot be zero")
	}
	if sandbox.SessionID == "" {
		return fmt.Errorf("sandbox sessionId cannot be empty")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	now := time.Now()
	expiresAtScore := float64(sandbox.ExpiresAt.Unix())
	lastActivityScore := float64(now.Unix())

	pipe := r.client.Pipeline()

	setCmd := pipe.SetNX(ctx, key, data, 0)
	expiryCmd := pipe.ZAdd(ctx, SessionExpiryKey, redis.Z{
		Score:  expiresAtScore,
		Member: sandbox.SessionID,
	})
	activityCmd := pipe.ZAdd(ctx, SessionLastActivity, redis.Z{
		Score:  lastActivityScore,
		Member: sandbox.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("pipeline failed: %w", err)
	}

	if !setCmd.Val() {
		return fmt.Errorf("sandbox already exists for session %s", sandbox.SessionID)
	}

	if !expiryCmd.Val() {
		return fmt.Errorf("failed to add to expiry index")
	}

	if !activityCmd.Val() {
		return fmt.Errorf("failed to add to last activity index")
	}

	return nil
}

func (r *RedisStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.SessionID == "" {
		return fmt.Errorf("sandbox sessionId cannot be empty")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	setXX := r.client.Set(ctx, key, data, 0)
	if setXX.Err() != nil {
		return fmt.Errorf("failed to update sandbox: %w", setXX.Err())
	}

	if !setXX.Val() {
		return fmt.Errorf("key not exists")
	}

	return nil
}

func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)

	pipe := r.client.Pipeline()
	delCmd := pipe.Del(ctx, key)
	zremExpiry := pipe.ZRem(ctx, SessionExpiryKey, sessionID)
	zremActivity := pipe.ZRem(ctx, SessionLastActivity, sessionID)

	_, err := pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("pipeline failed: %w", err)
	}

	if delCmd.Val() == 0 {
		return nil
	}

	return nil
}

func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return []*SandboxInfo{}, nil
	}

	maxScore := float64(before.Unix())

	result, err := r.client.ZRangeByScore(ctx, SessionExpiryKey, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatFloat(maxScore, 'f', -1, 64),
		Count: int64(limit),
	}).Result()

	if err != nil {
		return nil, fmt.Errorf("failed to list expired sandboxes: %w", err)
	}

	return r.loadSandboxesBySessionIDs(ctx, result)
}

func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return []*SandboxInfo{}, nil
	}

	maxScore := float64(before.Unix())

	result, err := r.client.ZRangeByScore(ctx, SessionLastActivity, &redis.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatFloat(maxScore, 'f', -1, 64),
		Count: int64(limit),
	}).Result()

	if err != nil {
		return nil, fmt.Errorf("failed to list inactive sandboxes: %w", err)
	}

	return r.loadSandboxesBySessionIDs(ctx, result)
}

func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("sessionId cannot be empty")
	}

	key := sessionKey(sessionID)
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return fmt.Errorf("failed to check session existence: %w", err)
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	score := float64(at.Unix())
	added, err := r.client.ZAdd(ctx, SessionLastActivity, redis.Z{
		Score:  score,
		Member: sessionID,
	}).Result()

	if err != nil {
		return fmt.Errorf("failed to update last activity: %w", err)
	}

	if !added {
		klog.Warningf("session %s not found in last_activity index, re-adding", sessionID)
	}

	return nil
}

func (r *RedisStore) Close() error {
	return r.client.Close()
}

func (r *RedisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	results, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to load sandboxes: %w", err)
	}

	sandboxes := make([]*SandboxInfo, 0, len(sessionIDs))
	for i, result := range results {
		if result == nil {
			continue
		}

		var sandbox SandboxInfo
		if err := json.Unmarshal([]byte(result.(string)), &sandbox); err != nil {
			klog.Warningf("failed to unmarshal sandbox %s: %v", sessionIDs[i], err)
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func sessionKey(sessionID string) string {
	return SessionKeyPrefix + sessionID
}

package store

import (
	"os"
	"strconv"
	"strings"
	"sync"

	"k8s.io/klog/v2"
)

const (
	ProviderRedis  = "redis"
	ProviderValkey = "valkey"
)

var (
	storeInstance Store
	storeOnce     sync.Once
)

type Config struct {
	StoreType            string
	RedisAddr            string
	RedisPassword        string
	RedisPasswordRequired bool
	ValkeyAddrs          []string
	ValkeyPassword       string
	ValkeyPasswordRequired bool
	ValkeyDisableCache   bool
	ValkeyForceSingle    bool
}

func LoadConfig() (*Config, error) {
	config := &Config{}

	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = ProviderRedis
	}
	storeType = strings.ToLower(storeType)
	config.StoreType = storeType

	if storeType != ProviderRedis && storeType != ProviderValkey {
		return nil, fmt.Errorf("unsupported store type: %s", storeType)
	}

	if storeType == ProviderValkey {
		valkeyAddr := os.Getenv("VALKEY_ADDR")
		if valkeyAddr == "" {
			return nil, fmt.Errorf("VALKEY_ADDR is required")
		}
		config.ValkeyAddrs = strings.Split(valkeyAddr, ",")

		config.ValkeyPassword = os.Getenv("VALKEY_PASSWORD")
		valkeyPasswordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
		if valkeyPasswordRequired == "" {
			valkeyPasswordRequired = "true"
		}
		config.ValkeyPasswordRequired = strings.ToLower(valkeyPasswordRequired) != "false"

		if config.ValkeyPasswordRequired && config.ValkeyPassword == "" {
			return nil, fmt.Errorf("VALKEY_PASSWORD is required")
		}

		disableCache := os.Getenv("VALKEY_DISABLE_CACHE")
		if disableCache != "" {
			config.ValkeyDisableCache, _ = strconv.ParseBool(disableCache)
		}

		forceSingle := os.Getenv("VALKEY_FORCE_SINGLE")
		if forceSingle != "" {
			config.ValkeyForceSingle, _ = strconv.ParseBool(forceSingle)
		}
	} else {
		config.RedisAddr = os.Getenv("REDIS_ADDR")
		if config.RedisAddr == "" {
			return nil, fmt.Errorf("REDIS_ADDR is required")
		}

		config.RedisPassword = os.Getenv("REDIS_PASSWORD")
		redisPasswordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
		if redisPasswordRequired == "" {
			redisPasswordRequired = "true"
		}
		config.RedisPasswordRequired = strings.ToLower(redisPasswordRequired) != "false"

		if config.RedisPasswordRequired && config.RedisPassword == "" {
			return nil, fmt.Errorf("REDIS_PASSWORD is required")
		}
	}

	return config, nil
}

func Storage() Store {
	storeOnce.Do(func() {
		config, err := LoadConfig()
		if err != nil {
			klog.Fatalf("failed to load store config: %v", err)
		}

		if config.StoreType == ProviderValkey {
			storeInstance, err = NewValkeyStore(
				config.ValkeyAddrs,
				config.ValkeyPassword,
				config.ValkeyDisableCache,
				config.ValkeyForceSingle,
			)
		} else {
			storeInstance, err = NewRedisStore(config.RedisAddr, config.RedisPassword)
		}

		if err != nil {
			klog.Fatalf("failed to initialize store: %v", err)
		}
	})

	return storeInstance
}

func CloseStorage() {
	if storeInstance != nil {
		storeInstance.Close()
	}
}

