package store

import (
	"context"
	"testing"
	"time"
)

func TestSessionKey(t *testing.T) {
	tests := []struct {
		name      string
		sessionID string
		expected  string
	}{
		{
			name:      "simple session id",
			sessionID: "abc",
			expected:  "session:abc",
		},
		{
			name:      "empty session id",
			sessionID: "",
			expected:  "session:",
		},
		{
			name:      "complex session id",
			sessionID: "test-session-123",
			expected:  "session:test-session-123",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := sessionKey(tt.sessionID)
			if result != tt.expected {
				t.Errorf("sessionKey(%q) = %q, want %q", tt.sessionID, result, tt.expected)
			}
		})
	}
}

func TestSandboxInfoSerialization(t *testing.T) {
	sandbox := &SandboxInfo{
		SandboxID: "sandbox-123",
		Name:      "test-sandbox",
		SessionID: "session-abc",
		Kind:      "AgentRuntime",
		Namespace: "default",
		EntryPoints: []EntryPoint{
			{
				Path:     "/api",
				Protocol: "HTTP",
				Endpoint: "10.0.0.1:8080",
				Name:     "main",
			},
		},
		ExpiresAt: time.Date(2026, 12, 31, 23, 59, 59, 0, time.UTC),
		CreatedAt: time.Now(),
	}

	if sandbox.SandboxID != "sandbox-123" {
		t.Errorf("expected SandboxID to be sandbox-123, got %s", sandbox.SandboxID)
	}
	if sandbox.SessionID != "session-abc" {
		t.Errorf("expected SessionID to be session-abc, got %s", sandbox.SessionID)
	}
	if len(sandbox.EntryPoints) != 1 {
		t.Errorf("expected 1 entry point, got %d", len(sandbox.EntryPoints))
	}
}

func TestStoreInterface(t *testing.T) {
	var _ Store = (*RedisStore)(nil)
	var _ Store = (*ValkeyStore)(nil)
}

func TestConfigLoadDefaults(t *testing.T) {
	t.Setenv("STORE_TYPE", "")
	t.Setenv("REDIS_ADDR", "localhost:6379")
	t.Setenv("REDIS_PASSWORD", "testpass")
	t.Setenv("REDIS_PASSWORD_REQUIRED", "true")

	config, err := LoadConfig()
	if err != nil {
		t.Fatalf("LoadConfig() error = %v", err)
	}

	if config.StoreType != ProviderRedis {
		t.Errorf("expected default store type redis, got %s", config.StoreType)
	}
}

func TestConfigRedisRequired(t *testing.T) {
	t.Setenv("STORE_TYPE", "redis")
	t.Setenv("REDIS_ADDR", "")
	t.Setenv("REDIS_PASSWORD", "")

	_, err := LoadConfig()
	if err == nil {
		t.Error("expected error for missing REDIS_ADDR, got nil")
	}
}

func TestConfigValkeyRequired(t *testing.T) {
	t.Setenv("STORE_TYPE", "valkey")
	t.Setenv("VALKEY_ADDR", "")
	t.Setenv("VALKEY_PASSWORD", "")

	_, err := LoadConfig()
	if err == nil {
		t.Error("expected error for missing VALKEY_ADDR, got nil")
	}
}

func TestConfigInvalidStoreType(t *testing.T) {
	t.Setenv("STORE_TYPE", "invalid")
	t.Setenv("REDIS_ADDR", "localhost:6379")

