package api

import (
	"errors"

	k8s_errors "k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

var (
	ErrAgentRuntimeNotFound   = errors.New("agentruntime not found")
	ErrCodeInterpreterNotFound = errors.New("codeinterpreter not found")
	ErrTemplateMissing        = errors.New("template missing")
	ErrPublicKeyMissing       = errors.New("public key missing")
)

func NewSessionNotFoundError(sessionID string) error {
	return k8s_errors.NewNotFound(
		metav1.GroupResource{
			Group:    "agentcube.volcano.sh",
			Resource: "sessions",
		},
		sessionID,
	)
}

func NewSandboxTemplateNotFoundError(namespace, name, kind string) error {
	groupResource := metav1.GroupResource{
		Group:    "runtime.agentcube.volcano.sh",
		Resource: "agentruntimes",
	}
	if kind == "CodeInterpreter" {
		groupResource.Resource = "codeinterpreters"
	}
	return k8s_errors.NewNotFound(groupResource, name)
}

